mapper.select:
SELECT r.id, r.student_id, u.real_name as student_name, c.class_name, r.course_id, co.course_name, r.requirement_id, req.title as requirement_title, req.deadline as deadline, r.title, r.content, r.file_path, r.file_name, r.file_type, r.status, r.create_time, r.update_time, e.id as evaluation_id, e.completeness_score, e.specification_score, e.knowledge_score, e.total_score, e.ai_evaluation, e.manual_evaluation, e.evaluate_time FROM training_report r LEFT JOIN sys_user u ON r.student_id = u.id LEFT JOIN sys_class c ON u.class_id = c.id LEFT JOIN course co ON r.course_id = co.id LEFT JOIN report_requirement req ON r.requirement_id = req.id LEFT JOIN evaluation_record e ON r.id = e.report_id
AND r.student_id = #{studentId}
AND r.course_id = #{courseId}
AND u.class_id = #{classId}
AND r.status = #{status}
ORDER BY r.create_time DESC
